from flask import request, redirect, Flask
from urllib.parse import urlparse

app = Flask(__name__)


@app.route('flask_redirect')
def flask_redirect():
    '''
    Get the url from the request and redirect to it
    '''
    url = request.args.get('url', '')

    # Validate URL to prevent open redirects (CWE-601)
    if not url:
        return redirect('/', code=302)

    parsed = urlparse(url)

    # Reject if scheme is present (e.g., http, https) or if netloc is present
    # Also reject protocol-relative URLs (e.g., //example.com)
    if parsed.scheme or parsed.netloc or url.startswith('//'):
        # Redirect to a safe default location instead of the unsafe URL
        return redirect('/', code=302)

    # Ensure the path does not contain newline or control characters
    if any(c in url for c in '\r\n\t'):
        return redirect('/', code=302)

    return redirect(url, code=302)
